<template>
  
  <v-container fluid>

    <v-toolbar flat color="white">
      <v-toolbar-title class="green--text">Members</v-toolbar-title>
      <v-divider
        class="mx-2"
        inset
        vertical
      ></v-divider>
      <v-spacer></v-spacer>
      <v-btn color="green lighten-1" dark class="mb-2">Export Data</v-btn>
    </v-toolbar>

    <v-toolbar
      slot="header"
      class="mt-2"
      color="green lighten-1"
      dark
      dense
      flat
    >
      <v-toolbar-title class="subheading">ID Pictures</v-toolbar-title>
    </v-toolbar>

    <amplify-s3-album :path="facePath" :s3AlbumConfig="imageOption"></amplify-s3-album>
    <v-toolbar
      slot="header"
      class="mt-2"
      color="green lighten-1"
      dark
      dense
      flat
    >
      <v-toolbar-title class="subheading">Member Pictures</v-toolbar-title>
    </v-toolbar>
    <amplify-s3-album :path="idPath" :s3AlbumConfig="imageOption"></amplify-s3-album>

    <v-toolbar
      slot="header"
      class="mt-2"
      color="green lighten-1"
      dark
      dense
      flat
    >
      <v-toolbar-title class="subheading">Member Information</v-toolbar-title>
    </v-toolbar>
    <v-data-iterator
      :items="members"
      :pagination.sync="pagination"
      content-tag="v-layout"
      hide-actions
      row
      wrap
    >

      <v-flex
        slot="item"
        slot-scope="props"
        xs6
        sm4
        md3
        lg2
      >
        <v-card>
          <v-card-title class="subheading font-weight-bold">Member No. {{ props.item.reservationCode }}-{{ props.item.memberNo }}</v-card-title>

          <v-divider></v-divider>

          <v-list dense>
            <v-list-tile>
              <v-list-tile-content>Last Name: {{ props.item.lastName }}</v-list-tile-content>
              <v-list-tile-content class="align-end"></v-list-tile-content>
            </v-list-tile>

            <v-list-tile>
              <v-list-tile-content>First Name: {{ props.item.firstName }}</v-list-tile-content>
              <v-list-tile-content class="align-end"></v-list-tile-content>
            </v-list-tile>

            <v-list-tile>
              <v-list-tile-content>ID Verified: {{ props.item.idVerified }}</v-list-tile-content>
              <!-- <v-list-tile-content class="align-end"> -->
              <v-switch :input-value="props.item.idVerified" @change="verifyId(props.item)"> </v-switch>
              <!-- </v-list-tile-content> -->
            </v-list-tile>

            <v-list-tile>
              <v-list-tile-content>ID Matches: {{ props.item.idMatches }}</v-list-tile-content>
              <v-switch :input-value="props.item.idMatches" @change="matchId(props.item)"></v-switch>
            </v-list-tile>
            
          </v-list>
        </v-card>
      </v-flex>
    </v-data-iterator>
  </v-container>
</template>


