<script>
import { mapState, mapGetters, mapActions } from 'vuex'
import { CallDialog } from '@/utils'
import store from '@/store'

export default {
  data: () => ({
    // rowsPerPageItems: [6, 8, 12],
    pagination: {
      rowsPerPage: 12
    }
  }),
  // created () {
  //   this.loadMembers(this.reservationCode).catch(error => {
  //     CallDialog(error)
  //   })
  // },

  async beforeRouteEnter (to, from, next) {
    console.log('store.state.host', store.state.host)

    const error = await store.dispatch('host/loadMembers', store.state.host.reservationCode).catch(error => {
      return error
    })

    if (error) {
      CallDialog(error)
    } else {
      next()
    }
  },
  async beforeRouteUpdate (to, from, next) {
    console.log('store.state.host', store.state.host)

    const error = await store.dispatch('host/loadMembers', store.state.host.reservationCode).catch(error => {      
      return error
    })

    if (error) {
      CallDialog(error)
    } else {
      next()
    }
  },
  computed: {
    imageOption () {
      return {
        // level: 'protected',
        identityId: this.identityId,
        level: 'protected'
      }
    },
    facePath () {
      return `${this.reservationCode}/face`
    },
    idPath () {
      return `${this.reservationCode}/id`
    },
    ...mapState({
      reservationCode: state => state.host.reservationCode,
      identityId: state => state.host.identityId,
      members: state => state.host.members
    }),
  },
  methods: {
    async verifyId (crtMember) {
      // if (!crtMember.idVerified) {
        crtMember.idVerified = !crtMember.idVerified

        const error = await this.updateMember(crtMember).catch(e => {
          console.error('updateMember', e)
          return e
        })

        CallDialog(error)
    },
    async matchId (crtMember) {
      // if (!crtMember.idVerified) {
        crtMember.idMatches = !crtMember.idMatches

        const error = await this.updateMember(crtMember).catch(e => {
          console.error('updateMember', e)
          return e
        })

        CallDialog(error)
    },   
    ...mapActions({
      loadMembers: 'host/loadMembers',
      updateMember: 'host/updateMember'
    })
  }
}
</script>